        public static string GetGuid(string eventPath)
        {
            if (EventToGuidMap.TryGetValue(eventPath, out var guid))
            {
                return guid;
            }
            // If not found, return the original event path as fallback
            return eventPath;
        }

        public static bool TryGetGuid(string eventPath, out string guid)
        {
            return EventToGuidMap.TryGetValue(eventPath, out guid);
        }
